import type { AccountSearchApi } from '@linm-soft/common-components';
import { masterService } from '../../services/master/masterService';

/** Single-field label — `152 — Nguyên liệu vật liệu` (align Finance + common-components). */
export function formatAccountDisplay(code: string, name?: string): string {
  const c = code?.trim() ?? '';
  const n = name?.trim() ?? '';
  if (c && n) return `${c} — ${n}`;
  return c || n;
}

/** Master MFE adapter — `GET /master/accounts`. */
export const erpMasterAccountSearchApi: AccountSearchApi = {
  search: async ({ search, page, pageSize, isActive, isDetail }) => {
    const res = await masterService.getAccounts({
      search,
      page,
      pageSize,
      isActive: isActive ?? true,
      isDetail,
    });
    return { items: res.items, page: res.page, totalCount: res.totalCount };
  },
  loadCatalog: async () => {
    const res = await masterService.getAccounts({ isActive: true, page: 1, pageSize: 500 });
    return res.items;
  },
};
